"use client";
import { Field, FieldLabel, FieldError } from "@/components/ui/field";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { useForm, Controller } from "react-hook-form";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { UploadImage } from "@/lib/data/images";

const BASE_URL = `${process.env.NEXT_PUBLIC_API}/api/v1`;

const formSchema = z.object({
  name: z.string().min(3, "Category name at least 3 characters long"),
});

type FormValues = z.infer<typeof formSchema>;

async function insertCategory(data: { name: string; image: string }) {
  const res = await fetch(`${BASE_URL}/categories`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });
  const resData = await res.json();
  console.log("Insert Category:", resData);
  return resData;
}

export default function CategoryForm() {
  const form = useForm<FormValues>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      name: "",
    },
  });

  async function onSubmit(values: FormValues) {
    const fileInput = document.querySelector<HTMLInputElement>("#category-image-input");
    const file = fileInput?.files?.[0];

    let imageUrl = "https://placehold.co/600x400/png";

    if (file) {
      const imageFormData = new FormData();
      imageFormData.append("file", file);
      const uploadedImage = await UploadImage(imageFormData);
      console.log("Uploaded image:", uploadedImage);
      imageUrl = uploadedImage.location;
    }

    await insertCategory({
      name: values.name,
      image: imageUrl,
    });

    form.reset();
  }

  function onReset() {
    form.reset();
    form.clearErrors();
  }

  return (
    <form
      onSubmit={form.handleSubmit(onSubmit)}
      onReset={onReset}
      className="space-y-8 @container"
    >
      <div className="grid grid-cols-12 gap-4">
        <Controller
          control={form.control}
          name="name"
          render={({ field, fieldState }) => (
            <Field
              className="col-span-12 flex flex-col gap-2 items-start"
              data-invalid={fieldState.invalid}
            >
              <FieldLabel>Category Name</FieldLabel>
              <Input placeholder="Electronics" type="text" {...field} />
              {fieldState.invalid && <FieldError errors={[fieldState.error]} />}
            </Field>
          )}
        />

        <Field className="col-span-12 flex flex-col gap-2 items-start">
          <FieldLabel>Category Image</FieldLabel>
          <Input
            id="category-image-input"
            type="file"
            accept="image/png,image/jpeg,image/jpg,image/gif"
          />
        </Field>

        <Field className="col-span-12 flex flex-col gap-2 items-start">
          <Button type="submit" variant="default" className="w-full">
            Submit
          </Button>
        </Field>

        <Field className="col-span-12 flex flex-col gap-2 items-start">
          <Button type="reset" variant="outline" className="w-full">
            Reset
          </Button>
        </Field>
      </div>
    </form>
  );
}